const text = $input.first().json.message.text;
const content = text.replace('/remember', '').trim();
const userId = String($input.first().json.message.from.id);
const chatId = $input.first().json.message.chat.id;
return [{ json: { content, user_id: userId, chat_id: chatId } }];

const text = $input.first().json.message.text;
const keyword = text.replace('/forget', '').trim();
const chatId = $input.first().json.message.chat.id;
return [{ json: { keyword, chat_id: chatId } }];

const triggerData = $('Telegram Trigger').first().json;
const isVoice = !!triggerData.message.voice;
let messageText;
if (isVoice) {
  messageText = $input.first().json.text; // Whisper output
} else {
  messageText = triggerData.message.text;
}
return [{ json: {
  message_text: messageText,
  user_id: String(triggerData.message.from.id),
  chat_id: triggerData.message.chat.id,
  first_name: triggerData.message.from.first_name || ''
} }];

const items = $input.all();
const normalised = $('Normalise Message Text').first().json;
const messageText = normalised.message_text;
const userId = normalised.user_id;
const chatId = normalised.chat_id;

let memoryContext = '';
if (items && items.length > 0 && Object.keys(items[0].json).length > 0) {
  memoryContext = 'DATABASE MEMORIES (STRICTLY USE THESE TO ANSWER THE QUESTION):\\n' +
    items.map((item, i) => {
      const m = item.json;
      const sim = m.similarity || 0;
      const label = sim >= 0.6 ? '[High confidence]' : '[Low confidence â€” verify before using]';
      return `${i+1}. ${label} [${(sim*100).toFixed(0)}% match] ${m.content}`;
    }).join('\\n') + '\\n\\n';
}

const brandPersona = 'You are a D2C brand intelligence assistant for Pure Remedy skincare. '
  + 'You have permanent memory of all past conversations. '
  + 'Always reference relevant past memories in your response. '
  + 'Save important brand info, supplier details, pricing, and customer insights automatically.';

// INJECT MEMORY INTO QUESTION TO FORCE FLOWISE TO READ IT INSTEAD OF RELYING ON SYSTEM PROMPT OR TOOLS
const finalQuestion = memoryContext ? (memoryContext + 'USER QUESTION:\\n' + messageText) : messageText;

return [{ json: {
  question: finalQuestion,
  session_id: userId,
  system_message: brandPersona,
  chat_id: chatId
} }];

const item = $input.first().json;
const scoreText = item.choices[0].message.content.trim();
const score = parseInt(scoreText);
const isImportant = !isNaN(score) && score >= 6;

return [{ json: { 
  is_important: isImportant, 
  importance_score: isImportant ? score : (isNaN(score) ? 0 : score),
  gpt_raw_response: scoreText
} }];

